import fs from "node:fs";
import path from "node:path";
import { execFileSync } from "node:child_process";

const output = path.resolve("src", "client", "openapi-types.ts");

fs.mkdirSync(path.dirname(output), { recursive: true });
execFileSync("npx", ["openapi-typescript", "docs/openapi.yaml", "-o", output], {
  stdio: "inherit",
});

const generated = fs.readFileSync(output, "utf8");
fs.writeFileSync(
  output,
  [
    "/* This file is generated by npm run client:generate. Do not edit by hand. */",
    generated,
  ].join("\n")
);
